const items = $input.all();
const first = items[0];
const body = first.json.body || first.json;
const url = body.url || first.json.url;

if (!url) {
  return [{ json: { status: 'error', message: 'No URL provided' } }];
}

try {
  const response = await this.helpers.httpRequest({
    method: 'GET',
    url: url,
    returnFullResponse: true,
    simple: false
  });

  const bodyText = typeof response.body === 'string' ? response.body : JSON.stringify(response.body);

  // Remove script, style, nav, footer, header content before extracting text
  let cleaned = bodyText
    .replace(/<script[^>]*>[\s\S]*?<\/script>/gi, ' ')
    .replace(/<style[^>]*>[\s\S]*?<\/style>/gi, ' ')
    .replace(/<nav[^>]*>[\s\S]*?<\/nav>/gi, ' ')
    .replace(/<footer[^>]*>[\s\S]*?<\/footer>/gi, ' ')
    .replace(/<header[^>]*>[\s\S]*?<\/header>/gi, ' ')
    .replace(/<[^>]+>/g, ' ')
    .replace(/&[a-z]+;/gi, ' ')
    .replace(/\s+/g, ' ')
    .trim();

  if (cleaned.length < 100) {
    return [{ json: { status: 'error', message: 'Content too short after cleaning', url: url } }];
  }

  const sentences = cleaned.split(/(?<=[.!?])\s+/).filter(s => s.length > 15);

  if (sentences.length < 5) {
    return [{ json: { status: 'error', message: 'Not enough sentences extracted', url: url, sentence_count: sentences.length } }];
  }

  const chunks = [];
  const chunkMaxChars = 600;
  const overlapChars = 80;
  let currentChunk = '';

  for (const sentence of sentences) {
    if ((currentChunk + ' ' + sentence).length > chunkMaxChars && currentChunk.length > 0) {
      chunks.push(currentChunk.trim());
      const words = currentChunk.split(' ');
      const overlapWords = words.slice(-Math.max(1, Math.floor(overlapChars / 5)));
      currentChunk = overlapWords.join(' ') + ' ' + sentence;
    } else {
      currentChunk += (currentChunk ? ' ' : '') + sentence;
    }
  }
  if (currentChunk.trim()) chunks.push(currentChunk.trim());

  if (chunks.length < 3) {
    return [{ json: { status: 'error', message: 'Not enough chunks generated', url: url, chunk_count: chunks.length } }];
  }

  return [{
    json: {
      status: 'ok',
      source_url: url,
      total_chunks: chunks.length,
      chunks: chunks.map((text, i) => ({
        chunk_index: i,
        text: text
      }))
    }
  }];
} catch (err) {
  return [{ json: { status: 'error', message: err.message, url: url } }];
}
